const ITERATIONS = 100_000;
const SALT_LENGTH = 16; // 128 bits
const KEY_LENGTH = 256; // bits = 32 bytes

function arrayBufferToBase64(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function base64ToArrayBuffer(base64: string): ArrayBuffer {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}

export async function hashPassword(password: string): Promise<string> {
  const salt = crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
  const encoder = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    'raw',
    encoder.encode(password),
    'PBKDF2',
    false,
    ['deriveBits'],
  );
  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: 'PBKDF2',
      salt,
      iterations: ITERATIONS,
      hash: 'SHA-256',
    },
    keyMaterial,
    KEY_LENGTH,
  );
  const saltBase64 = arrayBufferToBase64(salt.buffer);
  const hashBase64 = arrayBufferToBase64(derivedBits);
  return `${saltBase64}:${hashBase64}`;
}

export async function verifyPassword(
  password: string,
  storedHash: string,
): Promise<boolean> {
  const [saltBase64, hashBase64] = storedHash.split(':');
  const salt = base64ToArrayBuffer(saltBase64);
  const encoder = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    'raw',
    encoder.encode(password),
    'PBKDF2',
    false,
    ['deriveBits'],
  );
  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: 'PBKDF2',
      salt,
      iterations: ITERATIONS,
      hash: 'SHA-256',
    },
    keyMaterial,
    KEY_LENGTH,
  );
  const computedHashBase64 = arrayBufferToBase64(derivedBits);
  return computedHashBase64 === hashBase64;
}

import { defineApp } from 'rwsdk/worker';
import { route } from 'rwsdk/router';
import { drizzle } from 'drizzle-orm/d1';
import { users } from './db/schema';
import { eq } from 'drizzle-orm';
import { hashPassword, verifyPassword } from './lib/auth';

export default defineApp([
  route('/api/auth/register', {
    post: async ({ request }) => {
      let body: { email?: string; password?: string; displayName?: string };
      try {
        body = await request.json();
      } catch {
        return new Response(JSON.stringify({ error: 'Invalid JSON' }), {
          status: 400,
          headers: { 'Content-Type': 'application/json' },
        });
      }

      const { email, password, displayName } = body;

      if (!email || !password) {
        return new Response(
          JSON.stringify({ error: 'email and password are required' }),
          { status: 400, headers: { 'Content-Type': 'application/json' } },
        );
      }

      // Access D1 binding from env
      const db = drizzle((request as any).__env?.DB ?? (globalThis as any).__DB);

      // Check if user already exists
      const existing = await db
        .select()
        .from(users)
        .where(eq(users.email, email))
        .get();

      if (existing) {
        return new Response(
          JSON.stringify({ error: 'Email already exists' }),
          { status: 409, headers: { 'Content-Type': 'application/json' } },
        );
      }

      const passwordHash = await hashPassword(password);
      const now = new Date();

      const result = await db
        .insert(users)
        .values({
          email,
          passwordHash,
          createdAt: now,
          displayName: displayName ?? null,
        })
        .returning();

      const user = result[0];

      return new Response(
        JSON.stringify({
          id: user.id,
          email: user.email,
          displayName: user.displayName,
        }),
        { status: 201, headers: { 'Content-Type': 'application/json' } },
      );
    },
  }),

  route('/api/auth/login', {
    post: async ({ request }) => {
      let body: { email?: string; password?: string };
      try {
        body = await request.json();
      } catch {
        return new Response(JSON.stringify({ error: 'Invalid JSON' }), {
          status: 400,
          headers: { 'Content-Type': 'application/json' },
        });
      }

      const { email, password } = body;

      if (!email || !password) {
        return new Response(
          JSON.stringify({ error: 'email and password are required' }),
          { status: 400, headers: { 'Content-Type': 'application/json' } },
        );
      }

      const db = drizzle((request as any).__env?.DB ?? (globalThis as any).__DB);

      const user = await db
        .select()
        .from(users)
        .where(eq(users.email, email))
        .get();

      if (!user) {
        return new Response(
          JSON.stringify({ error: 'Invalid credentials' }),
          { status: 401, headers: { 'Content-Type': 'application/json' } },
        );
      }

      const valid = await verifyPassword(password, user.passwordHash);
      if (!valid) {
        return new Response(
          JSON.stringify({ error: 'Invalid credentials' }),
          { status: 401, headers: { 'Content-Type': 'application/json' } },
        );
      }

      return new Response(
        JSON.stringify({
          id: user.id,
          email: user.email,
          displayName: user.displayName,
        }),
        { status: 200, headers: { 'Content-Type': 'application/json' } },
      );
    },
  }),

  route('/api/users', {
    get: async ({ request }) => {
      const db = drizzle((request as any).__env?.DB ?? (globalThis as any).__DB);

      const allUsers = await db.select().from(users).all();

      return new Response(
        JSON.stringify(
          allUsers.map((u) => ({
            id: u.id,
            email: u.email,
            displayName: u.displayName,
            createdAt: u.createdAt instanceof Date ? u.createdAt.getTime() : u.createdAt,
          })),
        ),
        { status: 200, headers: { 'Content-Type': 'application/json' } },
      );
    },
  }),
]);

